import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract HexApeYachtClub is ERC721, Ownable, ReentrancyGuard {
    uint256 public constant MAX_SUPPLY = 10000;
    uint256 public immutable maxMintAmount = 20;
    uint256 public immutable price = 0.01 ether;
    string private _baseURIextended;
    uint256 private _totalSupply;

    constructor() ERC721("Hex Ape Yacht Club", "HAYC") {
        _totalSupply = 0;
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return _baseURIextended;
    }

    function setBaseURI(string memory baseURI) public onlyOwner {
        _baseURIextended = baseURI;
        emit BaseURIUpdated(baseURI);
    }

    function setPrice(uint256 newPrice) public onlyOwner {
        require(newPrice > 0, "Price must be greater than 0");
        price = newPrice;
        emit PriceUpdated(newPrice);
    }

    function mint(uint256 quantity) public payable nonReentrant {
        require(totalSupply() + quantity <= MAX_SUPPLY, "Exceeds maximum supply");
        require(quantity > 0 && quantity <= maxMintAmount, "Invalid mint amount");
        require(msg.value >= price * quantity, "Insufficient funds");

        for (uint256 i = 0; i < quantity; ++i) {
            uint256 tokenId = totalSupply();
            _safeMint(msg.sender, tokenId);
            _totalSupply++;
            emit NFTMinted(msg.sender, tokenId);
        }
    }

    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }

    function walletOfOwner(address _owner) public view returns (uint256[] memory) {
        uint256 ownerTokenCount = balanceOf(_owner);
        uint256[] memory tokenIds = new uint256[](ownerTokenCount);
        for (uint256 i; i < ownerTokenCount; ++i) {
            tokenIds[i] = tokenOfOwnerByIndex(_owner, i);
        }
        return tokenIds;
    }

    function withdraw() public onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        payable(owner()).transfer(balance);
        emit WithdrawalExecuted(balance);
    }

    function _burn(uint256 tokenId) internal override {
        super._burn(tokenId);
        _totalSupply--;
    }

    event NFTMinted(address indexed recipient, uint256 indexed tokenId);
    event PriceUpdated(uint256 newPrice);
    event BaseURIUpdated(string newBaseURI);
    event WithdrawalExecuted(uint256 amount);
}
