  - Use a proper reentrancy guard with a boolean flag to prevent reentrant calls.
  - Ensure the state change occurs after the external call to prevent race conditions.

  ```solidity
  pragma solidity ^0.8.7;

  import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

  contract SecureERC721 is ERC721, Ownable, ReentrancyGuard {
      bool private _locked;

      modifier nonReentrant() {
          require(!_locked, "No reentrancy");
          _locked = true;
          _;
          _locked = false;
      }

      function withdraw() public nonReentrant {
          uint256 balance = address(this).balance;
          payable(msg.sender).transfer(balance);
          emit WithdrawalExecuted(balance);
      }

      event WithdrawalExecuted(uint256 amount);
  }
